function buildDiamondProducts() {
  return DIAMOND_SERIES.map((s) => ({
    id: s.id,
    styleKey: s.id,
    nameZh: s.nameZh,
    nameEn: s.nameEn,
    descriptionZh: s.descriptionZh,
    descriptionEn: null,
    defaultColor: 'white',
    golds: [],
    carats: [...DIAMOND_CARATS],
    colors: ['white'],
    images: { white: [s.image] },
    weights: {},
    manualPrices: {},
    draft: false,
  }));
}

function sortGolds(golds) {
  const order = Object.fromEntries(METAL_DISPLAY_ORDER.map((g, i) => [g, i]));
  return [...golds].sort((a, b) => (order[a] ?? 99) - (order[b] ?? 99));
}

function imageUrl(filePath) {
  void filePath;
  return '';
}

function buildCatalogProduct(row) {
  const golds = sortGolds([...new Set(row.variants.map((v) => v.gold))]);
  const carats = [...new Set(row.variants.map((v) => v.carat))].sort();
  const weights = {};
  for (const v of row.variants) {
    (weights[v.gold] ||= {})[v.carat] = v.weightChin;
  }
  const styleKey = `${row.category}-${row.style}`;
  return {
    id: styleKey,
    styleKey,
    nameZh: row.nameZh,
    nameEn: null,
    descriptionZh: null,
    descriptionEn: null,
    defaultColor: row.defaultColor,
    golds,
    carats,
    colors: ['white', 'yellow', 'rose'],
    images: {},
    weights,
    manualPrices: {},
    draft: false,
  };
}

const categories = {};
